import type { CareerQuestion } from "./rrt-questions";

export const sonographyQuestionsBatch11: CareerQuestion[] = [
  { id: "sono-1006", stem: "A focal liver lesion that is hyperechoic with posterior acoustic enhancement on ultrasound is most consistent with:", options: ["Hemangioma","Hepatocellular carcinoma","Focal nodular hyperplasia","Metastatic disease"], correctIndex: 0, rationale: "Hemangiomas are the most common benign liver tumors. Typical appearance: well-defined, hyperechoic, homogeneous, with posterior acoustic enhancement due to their vascular nature.", difficulty: 2, category: "Abdominal Sonography", topic: "Liver Masses" },
  { id: "sono-1007", stem: "The 'parallel channel sign' (shotgun sign) in the liver indicates:", options: ["Dilated intrahepatic bile ducts running parallel to portal vein branches","Normal hepatic vasculature","Hepatic artery aneurysm","Portal vein thrombosis"], correctIndex: 0, rationale: "Normally only the portal vein is visible. When intrahepatic ducts dilate, they run parallel to portal branches creating the 'parallel channel' or 'shotgun' sign, indicating biliary obstruction.", difficulty: 2, category: "Abdominal Sonography", topic: "Biliary System" },
  { id: "sono-1008", stem: "A porcelain gallbladder on ultrasound shows:", options: ["Curvilinear calcification of the gallbladder wall with dense posterior shadowing","Simple gallstones","Gallbladder polyps","Sludge without wall changes"], correctIndex: 0, rationale: "Porcelain gallbladder: calcification within the gallbladder wall causing a curvilinear echogenic focus with shadowing. Associated with increased risk of gallbladder carcinoma.", difficulty: 3, category: "Abdominal Sonography", topic: "Gallbladder Pathology" },
  { id: "sono-1009", stem: "The 'starry sky' liver pattern on ultrasound is associated with:", options: ["Acute hepatitis with diffusely decreased liver echogenicity and bright portal triads","Cirrhosis","Normal liver","Fatty liver"], correctIndex: 0, rationale: "In acute hepatitis, the liver parenchyma becomes diffusely hypoechoic (edematous) while portal triad walls remain bright, creating a 'starry sky' appearance.", difficulty: 3, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-1010", stem: "Nutcracker syndrome involves compression of:", options: ["The left renal vein between the aorta and SMA","The right renal artery","The celiac trunk","The IVC by the liver"], correctIndex: 0, rationale: "Nutcracker syndrome: the left renal vein is compressed between the aorta posteriorly and SMA anteriorly, causing venous hypertension, hematuria, and left flank pain.", difficulty: 4, category: "Vascular Sonography", topic: "Venous Compression" },
  { id: "sono-1011", stem: "May-Thurner syndrome involves:", options: ["Compression of the left common iliac vein by the right common iliac artery against the lumbar spine","Compression of the right iliac vein","Arterial occlusion of the femoral artery","Bilateral DVT"], correctIndex: 0, rationale: "May-Thurner: the left common iliac vein is compressed between the right common iliac artery and L5 vertebra, predisposing to left lower extremity DVT.", difficulty: 4, category: "Vascular Sonography", topic: "Venous Compression" },
  { id: "sono-1012", stem: "A tardus-parvus waveform in the intrarenal arteries suggests:", options: ["Significant proximal renal artery stenosis","Normal renal perfusion","Renal vein thrombosis","Hydronephrosis"], correctIndex: 0, rationale: "Tardus-parvus: delayed upstroke (tardus) and diminished peak (parvus) in intrarenal arteries, indicating dampened flow from a proximal hemodynamically significant renal artery stenosis.", difficulty: 3, category: "Vascular Sonography", topic: "Renal Doppler" },
  { id: "sono-1013", stem: "The normal common bile duct (CBD) diameter in adults is:", options: ["Up to 6mm (7mm if post-cholecystectomy)","Up to 2mm","10-15mm","Greater than 12mm is normal"], correctIndex: 0, rationale: "Normal CBD: ≤6mm (some use ≤7mm). Post-cholecystectomy: up to 10mm may be normal. The CBD may dilate slightly with age (~1mm per decade after age 60).", difficulty: 1, category: "Abdominal Sonography", topic: "Biliary System" },
  { id: "sono-1014", stem: "A Krukenberg tumor is:", options: ["Metastatic disease to the ovary, most commonly from gastric or colon primary cancer","A primary ovarian neoplasm","A uterine fibroid","A benign adrenal mass"], correctIndex: 0, rationale: "Krukenberg tumors are metastases to the ovaries, classically from gastric cancer (signet ring cells). They typically appear as bilateral solid ovarian masses.", difficulty: 3, category: "OB/GYN Sonography", topic: "Ovarian Pathology" },
  { id: "sono-1015", stem: "Polyhydramnios is defined as:", options: ["Amniotic fluid index (AFI) >24cm or single deepest pocket >8cm","AFI <5cm","AFI between 5-24cm","Normal amniotic fluid volume"], correctIndex: 0, rationale: "Polyhydramnios: excessive amniotic fluid. AFI >24cm or SDP >8cm. Causes include fetal GI obstruction, neural tube defects, maternal diabetes, twin-twin transfusion (recipient).", difficulty: 2, category: "OB/GYN Sonography", topic: "Amniotic Fluid" },
  { id: "sono-1016", stem: "Oligohydramnios is defined as:", options: ["AFI <5cm or single deepest pocket <2cm","AFI >24cm","Normal fluid for gestational age","AFI between 10-20cm"], correctIndex: 0, rationale: "Oligohydramnios: AFI <5cm or SDP <2cm. Causes include PPROM, renal agenesis, obstructive uropathy, IUGR, and post-dates pregnancy.", difficulty: 2, category: "OB/GYN Sonography", topic: "Amniotic Fluid" },
  { id: "sono-1017", stem: "A biophysical profile (BPP) assesses:", options: ["Fetal breathing movements, gross body movements, fetal tone, amniotic fluid volume, and non-stress test","Only fetal heart rate","Only amniotic fluid","Only fetal movement"], correctIndex: 0, rationale: "BPP scores 5 parameters (2 points each, max 10): breathing, movement, tone, AFV (ultrasound), and NST. Score ≤4 is abnormal; 6 is equivocal; 8-10 is reassuring.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Assessment" },
  { id: "sono-1018", stem: "The middle cerebral artery (MCA) peak systolic velocity is used to assess:", options: ["Fetal anemia — elevated MCA-PSV (>1.5 MoM) indicates moderate-severe anemia","Fetal weight","Gestational age","Fetal lung maturity"], correctIndex: 0, rationale: "Elevated MCA-PSV indicates fetal anemia (Rh isoimmunization, TTTS, parvovirus). >1.5 MoM suggests moderate-severe anemia. Has largely replaced invasive amniocentesis for anemia screening.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Doppler" },
  { id: "sono-1019", stem: "Placenta previa is diagnosed when:", options: ["The placenta covers or is within 2cm of the internal cervical os after 16 weeks","The placenta is fundal","The placenta is lateral","The placenta is posterior but away from the os"], correctIndex: 0, rationale: "Placenta previa: placenta covers/overlaps the internal os. Classified as complete (covers os), partial, or marginal (<2cm from os). Transvaginal US is the gold standard.", difficulty: 2, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-1020", stem: "Vasa previa on ultrasound shows:", options: ["Fetal vessels crossing the internal cervical os, identified by color Doppler","Placental abruption","Cervical polyp","Normal umbilical cord"], correctIndex: 0, rationale: "Vasa previa: unprotected fetal vessels crossing the internal os. Diagnosed by transvaginal US with color Doppler. Rupture causes rapid fetal exsanguination. Elective cesarean is planned.", difficulty: 4, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-1021", stem: "Gastroschisis differs from omphalocele in that:", options: ["Gastroschisis has no covering membrane, is typically right-sided, and rarely has associated chromosomal abnormalities","Gastroschisis always has a membrane covering","Omphalocele is right-sided","They are identical conditions"], correctIndex: 0, rationale: "Gastroschisis: right paraumbilical defect, no membrane, bowel floats freely in amniotic fluid, low chromosomal risk. Omphalocele: midline, membrane-covered, associated with trisomy.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-1022", stem: "Anencephaly on prenatal ultrasound shows:", options: ["Absent cranial vault above the orbits with exposed brain tissue ('frog face' appearance)","Normal fetal head","Enlarged ventricles only","Small but intact skull"], correctIndex: 0, rationale: "Anencephaly: absence of cranial vault and cerebral hemispheres above the orbits. Diagnosable by late first trimester. Incompatible with extrauterine life.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-1023", stem: "Spina bifida on ultrasound may show:", options: ["'Lemon sign' (frontal bone scalloping) and 'banana sign' (cerebellar shape) with splaying of posterior vertebral elements","Normal spine appearance in all cases","Only head abnormalities","Absent limbs"], correctIndex: 0, rationale: "Open spina bifida: splayed posterior elements, lemon-shaped skull (frontal scalloping), banana-shaped cerebellum (compressed), and ventriculomegaly (Chiari II malformation).", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-1024", stem: "Congenital diaphragmatic hernia (CDH) on prenatal ultrasound shows:", options: ["Abdominal organs (stomach, bowel, liver) in the thorax with mediastinal shift and a small abdominal circumference","Enlarged abdominal circumference","Pleural effusion only","Normal thorax and abdomen"], correctIndex: 0, rationale: "CDH: herniation of abdominal viscera through a diaphragmatic defect (usually left-sided Bochdalek type). Causes pulmonary hypoplasia and mediastinal shift. Prognosis depends on lung volume.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-1025", stem: "Thanatophoric dysplasia, a lethal skeletal dysplasia, shows:", options: ["Severely shortened limbs, narrow thorax, macrocephaly with cloverleaf skull deformity (type II), and platyspondyly","Normal limb length","Long limbs","Absent limbs"], correctIndex: 0, rationale: "Thanatophoric dysplasia: the most common lethal skeletal dysplasia. Features: severe micromelia, narrow 'bell-shaped' thorax, macrocephaly, and platyspondyly. Usually fatal due to pulmonary hypoplasia.", difficulty: 4, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-1026", stem: "Echogenic intracardiac focus (EIF) seen in the fetal heart is:", options: ["Usually a normal variant (papillary muscle calcification) that may be a soft marker for trisomy 21 when isolated","Always pathological","An indication for immediate delivery","A sign of cardiac malformation"], correctIndex: 0, rationale: "EIF is a small echogenic focus in the fetal ventricle, usually benign. As an isolated finding, it slightly increases trisomy 21 risk but does not warrant invasive testing alone.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Markers" },
  { id: "sono-1027", stem: "A choroid plexus cyst in the fetus is:", options: ["Usually a benign finding that resolves by 26 weeks; when isolated, has minimal clinical significance","Always associated with trisomy 18","An indication for termination","A brain tumor"], correctIndex: 0, rationale: "Choroid plexus cysts are common (1-2% of fetuses), usually resolve by 26 weeks. Isolated CPCs have minimal significance. Multiple/bilateral CPCs with other markers increase trisomy 18 risk.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Markers" },
  { id: "sono-1028", stem: "The normal ductus venosus waveform in the fetus shows:", options: ["Forward flow throughout the cardiac cycle with a prominent a-wave (positive)","Reversed a-wave flow","Absent flow","Continuous non-pulsatile flow"], correctIndex: 0, rationale: "Normal ductus venosus: triphasic forward flow with S-wave (systole), D-wave (diastole), and positive a-wave (atrial contraction). Reversed a-wave suggests cardiac dysfunction or aneuploidy.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Doppler" },
  { id: "sono-1029", stem: "Cystic hygroma in the first trimester is associated with:", options: ["Chromosomal abnormalities (especially Turner syndrome 45,X) and may indicate fetal hydrops","Normal pregnancy","Gestational diabetes","Advanced maternal age only"], correctIndex: 0, rationale: "First trimester cystic hygroma (large septated lymphatic malformation in the posterior neck) is strongly associated with aneuploidy, especially Turner syndrome (45,X), trisomy 21, and 18.", difficulty: 3, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-1030", stem: "A succenturiate lobe of the placenta is:", options: ["An accessory lobe of placental tissue connected to the main placenta by membranes containing vessels","A normal placental variant with no significance","A molar pregnancy variant","Placental abruption"], correctIndex: 0, rationale: "Succenturiate lobe: accessory placental lobe connected by vessels running through membranes. Risk of vasa previa if vessels cross the os. Retained lobe causes postpartum hemorrhage.", difficulty: 3, category: "OB/GYN Sonography", topic: "Placental Variants" },
  { id: "sono-1031", stem: "Fetal renal agenesis (bilateral) is associated with:", options: ["Potter sequence (oligohydramnios, pulmonary hypoplasia, limb deformities, facial compression)","Normal amniotic fluid","Polyhydramnios","No significant complications"], correctIndex: 0, rationale: "Bilateral renal agenesis: no fetal urine production → severe oligohydramnios → pulmonary hypoplasia (lethal) → Potter sequence. Empty renal fossae and no bladder filling on US.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-1032", stem: "The normal resistive index of the uterine artery in the third trimester is:", options: ["Less than 0.58 with absence of early diastolic notching","Greater than 0.80","No diastolic flow","Reversed diastolic flow"], correctIndex: 0, rationale: "Normal uterine artery: low resistance (RI <0.58) with no early diastolic notch in the third trimester. Persistent notching and high RI are associated with preeclampsia and IUGR.", difficulty: 3, category: "OB/GYN Sonography", topic: "Uterine Artery Doppler" },
  { id: "sono-1033", stem: "Acoustic streaming (microstreaming) is a bioeffect of ultrasound that:", options: ["Involves small-scale fluid currents near oscillating surfaces or bubbles that can affect cell membrane permeability","Is a thermal effect only","Has no clinical relevance","Only occurs at very low frequencies"], correctIndex: 0, rationale: "Acoustic streaming/microstreaming: ultrasound creates fluid currents near boundaries and microbubbles. At diagnostic levels, effects are minimal but are considered in ALARA practice.", difficulty: 4, category: "Ultrasound Physics & Instrumentation", topic: "Bioeffects" },
  { id: "sono-1034", stem: "Coded excitation in ultrasound imaging:", options: ["Uses encoded pulse sequences to improve signal-to-noise ratio and penetration while maintaining resolution","Decreases image quality","Only works at surface depths","Eliminates all artifacts"], correctIndex: 0, rationale: "Coded excitation transmits longer encoded pulses and decodes returns to achieve better SNR and penetration without sacrificing resolution. Useful in difficult-to-scan patients.", difficulty: 4, category: "Ultrasound Physics & Instrumentation", topic: "Advanced Techniques" },
  { id: "sono-1035", stem: "A hepatic hemangioma that is atypical in appearance requires:", options: ["Further characterization with contrast-enhanced CT, MRI, or CEUS to differentiate from malignancy","Immediate biopsy","No follow-up","Surgical removal"], correctIndex: 0, rationale: "Atypical hemangiomas (hypoechoic, heterogeneous, large) cannot be confidently diagnosed by B-mode US alone. Cross-sectional imaging (MRI with contrast or CEUS) confirms the diagnosis.", difficulty: 3, category: "Abdominal Sonography", topic: "Liver Masses" },
  { id: "sono-1036", stem: "The Courvoisier sign refers to:", options: ["A palpable, non-tender, distended gallbladder in the setting of painless jaundice, suggesting malignant biliary obstruction","Murphy's sign","Cullen's sign","Grey Turner's sign"], correctIndex: 0, rationale: "Courvoisier's law: painless jaundice with palpable gallbladder suggests malignant (pancreatic head) obstruction. Gallstone obstruction typically causes a contracted, fibrosed gallbladder.", difficulty: 3, category: "Abdominal Sonography", topic: "Biliary Pathology" },
  { id: "sono-1037", stem: "Hepatic steatosis (fatty liver) on ultrasound shows:", options: ["Diffusely increased liver echogenicity compared to the renal cortex with posterior beam attenuation","Decreased liver echogenicity","Normal liver echogenicity","Focal hypoechoic mass"], correctIndex: 0, rationale: "Fatty liver: increased parenchymal echogenicity > renal cortex, posterior beam attenuation, poor visualization of diaphragm and deep structures, and loss of portal vein wall echogenicity.", difficulty: 1, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-1038", stem: "Cirrhosis on ultrasound characteristically shows:", options: ["Small, nodular liver with coarsened echotexture, caudate lobe hypertrophy, ascites, and signs of portal hypertension","Enlarged, smooth liver","Normal liver appearance","Focal mass without parenchymal changes"], correctIndex: 0, rationale: "Cirrhosis: shrunken liver, surface nodularity, coarsened heterogeneous echotexture, caudate hypertrophy, signs of portal hypertension (ascites, splenomegaly, varices, reversed portal flow).", difficulty: 2, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-1039", stem: "A focal fatty sparing area in the liver typically occurs:", options: ["Adjacent to the gallbladder fossa or portal vein, appearing hypoechoic relative to the surrounding fatty liver","In the dome of the liver","At the hepatic hilum","Throughout the liver uniformly"], correctIndex: 0, rationale: "Focal fatty sparing: areas of normal liver within a fatty liver, appearing relatively hypoechoic. Common locations: gallbladder fossa, portal vein area. Does not cause mass effect.", difficulty: 2, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-1040", stem: "A Klatskin tumor is a cholangiocarcinoma located at:", options: ["The hepatic duct bifurcation (confluence of right and left hepatic ducts)","The distal CBD","The gallbladder","The ampulla of Vater"], correctIndex: 0, rationale: "Klatskin tumor: hilar cholangiocarcinoma at the hepatic duct confluence. Causes intrahepatic ductal dilation with normal extrahepatic ducts. Classified by Bismuth-Corlette system.", difficulty: 4, category: "Abdominal Sonography", topic: "Biliary Malignancy" },
  { id: "sono-1041", stem: "Mirizzi syndrome occurs when:", options: ["A gallstone impacted in the cystic duct or Hartmann's pouch compresses the common hepatic duct causing biliary obstruction","The CBD is occluded by pancreatic cancer","The gallbladder is absent","Portal vein compression occurs"], correctIndex: 0, rationale: "Mirizzi syndrome: extrinsic compression of the CHD by a large stone in the cystic duct/gallbladder neck. May cause bile duct erosion and cholecystobiliary fistula.", difficulty: 4, category: "Abdominal Sonography", topic: "Biliary Pathology" },
  { id: "sono-1042", stem: "Emphysematous cholecystitis on ultrasound shows:", options: ["Gas within the gallbladder wall producing 'dirty shadowing' and ring-down artifact","Simple gallstones with clean shadow","Normal gallbladder","Porcelain gallbladder appearance"], correctIndex: 0, rationale: "Emphysematous cholecystitis: gas-forming bacterial infection of the gallbladder wall. Gas produces dirty shadowing/ring-down artifact. Emergency: high perforation and mortality risk. Common in diabetics.", difficulty: 3, category: "Abdominal Sonography", topic: "Gallbladder Pathology" },
  { id: "sono-1043", stem: "The 'whirlpool sign' on ultrasound is associated with:", options: ["Mesenteric or ovarian torsion — a twisted vascular pedicle seen on color Doppler","Normal bowel peristalsis","Renal cyst","Hepatic hemangioma"], correctIndex: 0, rationale: "The whirlpool sign represents a twisted vascular pedicle seen as a circular flow pattern on color Doppler. Seen in mesenteric volvulus and ovarian/adnexal torsion.", difficulty: 3, category: "Abdominal Sonography", topic: "Acute Abdomen" },
  { id: "sono-1044", stem: "Autosomal dominant polycystic kidney disease (ADPKD) on ultrasound shows:", options: ["Bilaterally enlarged kidneys with multiple cysts of varying sizes replacing the parenchyma","Small echogenic kidneys","Unilateral single cyst","Normal kidney appearance"], correctIndex: 0, rationale: "ADPKD: bilateral, multiple cysts of varying sizes, progressive renal enlargement, loss of corticomedullary differentiation. Hepatic and pancreatic cysts may coexist. Leading cause of hereditary renal failure.", difficulty: 2, category: "Abdominal Sonography", topic: "Renal Pathology" },
  { id: "sono-1045", stem: "Renal cell carcinoma on ultrasound typically appears as:", options: ["A solid, heterogeneous mass that may be iso- to hyperechoic, with internal vascularity on color Doppler","A simple anechoic cyst","A calcified mass always","An echogenic focus without mass effect"], correctIndex: 0, rationale: "RCC: solid renal mass, often heterogeneous (necrosis, hemorrhage), variable echogenicity. May demonstrate internal vascularity. Small RCCs may appear hyperechoic, mimicking angiomyolipoma.", difficulty: 2, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-1046", stem: "A renal angiomyolipoma (AML) typically appears as:", options: ["Small, well-defined, homogeneously hyperechoic mass with possible posterior acoustic shadowing from fat","Hypoechoic mass with flow","Complex cystic mass","Hydronephrotic kidney"], correctIndex: 0, rationale: "AML contains fat, smooth muscle, and blood vessels. Small AMLs are characteristically hyperechoic (fat content). Large AMLs may be heterogeneous. Associated with tuberous sclerosis.", difficulty: 2, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-1047", stem: "Xanthogranulomatous pyelonephritis (XGP) on ultrasound shows:", options: ["Enlarged kidney with multiple hypoechoic areas replacing the parenchyma, often with central calcified staghorn calculus","Normal kidney appearance","Simple cortical cyst","Small echogenic kidney"], correctIndex: 0, rationale: "XGP: chronic destructive granulomatous infection, usually associated with staghorn calculus. Kidney is non-functioning with parenchyma replaced by xanthomatous tissue. May mimic RCC.", difficulty: 4, category: "Abdominal Sonography", topic: "Renal Infection" },
  { id: "sono-1048", stem: "An adrenal pheochromocytoma on ultrasound appears as:", options: ["Well-defined, round, solid suprarenal mass that may have areas of hemorrhage or cystic degeneration","Always small and calcified","Bilateral tiny nodules","Indistinguishable from normal adrenal"], correctIndex: 0, rationale: "Pheochromocytomas: solid adrenal masses, often >3cm, may have hemorrhage/necrosis creating complex appearance. Clinical: hypertension, headaches, palpitations, sweating.", difficulty: 3, category: "Abdominal Sonography", topic: "Adrenal Masses" },
  { id: "sono-1049", stem: "The 'ring of fire' sign on transvaginal ultrasound with color Doppler is seen in:", options: ["Ectopic pregnancy — circumferential hypervascularity around the ectopic gestational sac (tubal ring)","Ovarian cyst","Normal corpus luteum","Uterine fibroid"], correctIndex: 0, rationale: "Ring of fire: intense peripheral vascularity surrounding an ectopic gestational sac on color Doppler. Note: corpus luteum can also show this pattern; clinical correlation is essential.", difficulty: 3, category: "OB/GYN Sonography", topic: "Ectopic Pregnancy" },
  { id: "sono-1050", stem: "A theca lutein cyst is associated with:", options: ["Markedly elevated beta-hCG levels (gestational trophoblastic disease, multiple pregnancies, ovarian hyperstimulation)","Low hCG levels","Postmenopausal state","Normal singleton pregnancy typically"], correctIndex: 0, rationale: "Theca lutein cysts result from excessive hCG stimulation: bilateral, large, multiloculated ovarian cysts. Seen in GTD (molar pregnancy), multiple gestations, and OHSS.", difficulty: 3, category: "OB/GYN Sonography", topic: "Ovarian Pathology" },
  { id: "sono-1051", stem: "Doppler assessment of the middle cerebral artery in suspected fetal growth restriction:", options: ["Shows 'brain-sparing' effect with decreased PI/RI indicating preferential blood flow redistribution to the brain","Shows increased resistance in the MCA","Is not useful in IUGR assessment","Demonstrates absent flow"], correctIndex: 0, rationale: "In IUGR, fetal blood flow redistributes to vital organs (brain, heart, adrenals). MCA shows decreased resistance (brain-sparing). CPR (cerebro-placental ratio) <1 is abnormal.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Doppler" },
  { id: "sono-1052", stem: "Heterotopic pregnancy (simultaneous intrauterine and ectopic pregnancy) is:", options: ["Rare spontaneously but more common with assisted reproduction techniques (1:100 with IVF)","More common than isolated ectopic","Impossible to diagnose by ultrasound","Only theoretical"], correctIndex: 0, rationale: "Heterotopic pregnancy: coexisting IUP and ectopic. Spontaneous incidence ~1:30,000 but rises to ~1:100 with ART. The IUP may mask ectopic symptoms, delaying diagnosis.", difficulty: 3, category: "OB/GYN Sonography", topic: "Ectopic Pregnancy" },
  { id: "sono-1053", stem: "A cervical ectopic pregnancy on ultrasound shows:", options: ["Gestational sac implanted within the cervical canal below the internal os with peritrophoblastic flow","Normal intrauterine pregnancy","Cervical polyp","Nabothian cyst"], correctIndex: 0, rationale: "Cervical ectopic: sac within the cervix, empty uterus, barrel-shaped cervix, peritrophoblastic flow. 'Sliding sign' negative (sac doesn't move with probe pressure, unlike miscarriage in transit).", difficulty: 4, category: "OB/GYN Sonography", topic: "Ectopic Pregnancy" },
  { id: "sono-1054", stem: "Fetal hydrops (non-immune) on ultrasound shows:", options: ["Fluid accumulation in at least two fetal compartments: ascites, pleural effusion, pericardial effusion, or skin edema","Single small pleural effusion","Polyhydramnios only","Normal fetal appearance"], correctIndex: 0, rationale: "Non-immune hydrops: fluid in ≥2 compartments. Causes: cardiac anomalies, chromosomal, infections (parvovirus, CMV), anemia, TTTS, structural anomalies. Placentomegaly often coexists.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Pathology" },
  { id: "sono-1055", stem: "The sonographic measurement of the fetal cerebellum correlates with:", options: ["Gestational age in weeks (cerebellar diameter in mm ≈ GA in weeks until about 20 weeks)","Fetal weight only","Amniotic fluid volume","Placental grade"], correctIndex: 0, rationale: "Transverse cerebellar diameter in mm approximates gestational age in weeks up to ~20 weeks. Useful for dating when other parameters are discordant.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Biometry" },
  { id: "sono-1056", stem: "A Dandy-Walker malformation on fetal ultrasound shows:", options: ["Complete or partial agenesis of the cerebellar vermis with cystic dilation of the fourth ventricle and enlargement of the posterior fossa","Normal cerebellum","Enlarged lateral ventricles only","Agenesis of the corpus callosum only"], correctIndex: 0, rationale: "Dandy-Walker: absent/hypoplastic cerebellar vermis, cystic fourth ventricle communicating with posterior fossa, enlarged posterior fossa, elevated tentorium. Associated with hydrocephalus.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal CNS Anomalies" },
  { id: "sono-1057", stem: "Holoprosencephaly is a spectrum of brain malformations where:", options: ["The prosencephalon fails to divide into cerebral hemispheres — alobar (most severe), semilobar, and lobar types","The cerebellum is absent","Only the brainstem is affected","The ventricles are normal"], correctIndex: 0, rationale: "Holoprosencephaly: failure of forebrain cleavage. Alobar: single ventricle, fused thalami, no midline structures. Semilobar: partial separation. Lobar: nearly complete separation.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal CNS Anomalies" },
  { id: "sono-1058", stem: "Umbilical cord with only two vessels (single umbilical artery) is associated with:", options: ["Increased risk of renal anomalies, cardiac defects, and chromosomal abnormalities","No clinical significance","Only cosmetic concerns","Macrosomia"], correctIndex: 0, rationale: "Two-vessel cord (SUA): absent one umbilical artery. Associated with renal anomalies, cardiac defects, IUGR, and aneuploidy. Detailed anatomic survey recommended when identified.", difficulty: 2, category: "OB/GYN Sonography", topic: "Umbilical Cord" },
  { id: "sono-1059", stem: "In musculoskeletal ultrasound, a normal tendon appears:", options: ["As a fibrillar, hyperechoic structure with parallel echogenic lines representing collagen bundles","Anechoic like fluid","Hypoechoic and homogeneous","Hyperechoic without internal structure"], correctIndex: 0, rationale: "Normal tendons show a characteristic fibrillar pattern: parallel hyperechoic lines (collagen fascicles) with intervening hypoechoic endotenon. Anisotropy affects appearance at oblique angles.", difficulty: 2, category: "Small Parts & Superficial", topic: "Musculoskeletal" },
  { id: "sono-1060", stem: "Anisotropy artifact in tendon imaging:", options: ["Causes artificial hypoechogenicity when the ultrasound beam is not perpendicular to the tendon fibers","Is always pathological","Cannot be corrected","Only occurs with linear transducers"], correctIndex: 0, rationale: "Anisotropy: tendons appear artifactually hypoechoic when the beam is not perpendicular. Corrected by adjusting the transducer angle to be perpendicular. Mimics tendinopathy if not recognized.", difficulty: 2, category: "Small Parts & Superficial", topic: "Musculoskeletal" },
  { id: "sono-1061", stem: "The 'twinkling artifact' on color Doppler is seen posterior to:", options: ["Strongly reflecting irregular surfaces such as calculi or calcifications, mimicking blood flow","Moving blood","Soft tissue masses","Fluid collections"], correctIndex: 0, rationale: "Twinkling artifact: rapidly alternating color Doppler signal behind highly reflective irregular surfaces (kidney stones, gallstones, calcifications). Useful for detecting small calculi.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Artifacts" },
  { id: "sono-1062", stem: "B-flow imaging in ultrasound:", options: ["Directly displays blood flow echoes without relying on Doppler frequency shifts, providing high-resolution vascular imaging","Is a Doppler-based technique","Measures tissue elasticity","Only works in cardiac imaging"], correctIndex: 0, rationale: "B-flow amplifies blood cell reflections using coded excitation, providing direct visualization of flow without Doppler aliasing or angle dependence. Useful for vascular and cardiac assessment.", difficulty: 4, category: "Ultrasound Physics & Instrumentation", topic: "Advanced Techniques" },
  { id: "sono-1063", stem: "The propagation speed artifact occurs when:", options: ["Sound travels through tissue at a speed different from the assumed 1540 m/s, causing depth (range) errors","The transducer frequency is too high","The PRF is too low","Gain is set too high"], correctIndex: 0, rationale: "If actual speed differs from assumed 1540 m/s (e.g., fat at 1450), the calculated depth will be incorrect — too deep if speed is slower, too shallow if faster.", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Artifacts" },
  { id: "sono-1064", stem: "Persistence (temporal averaging/frame averaging) in ultrasound:", options: ["Averages multiple frames to reduce noise and improve image smoothness, but may reduce temporal resolution","Increases spatial resolution","Eliminates all artifacts","Only affects Doppler imaging"], correctIndex: 0, rationale: "Persistence averages successive frames to reduce random noise (speckle). Higher persistence = smoother image but reduced temporal resolution (blurring of moving structures).", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Image Optimization" },
  { id: "sono-1065", stem: "A patient with a transplant kidney has an elevated resistive index of 0.85 in the intrarenal arteries. This finding suggests:", options: ["Possible transplant rejection, renal vein thrombosis, or other intrinsic renal pathology requiring clinical correlation","Normal transplant function","Renal artery stenosis at the anastomosis","No clinical significance"], correctIndex: 0, rationale: "Elevated RI >0.80 in transplant kidneys suggests rejection, ATN, drug toxicity, renal vein thrombosis, or obstruction. Not specific — requires clinical and possibly biopsy correlation.", difficulty: 3, category: "Abdominal Sonography", topic: "Transplant Monitoring" },
  { id: "sono-1066", stem: "A thyroid nodule with spongiform appearance (multiple microcystic components) is:", options: ["Highly likely benign with a very low malignancy risk","Highly suspicious for malignancy","An indication for immediate surgery","Always associated with hyperthyroidism"], correctIndex: 0, rationale: "Spongiform thyroid nodules (aggregate of microcystic components >50% of volume) have very low malignancy risk (<2%). Often classified as TI-RADS 2 (not suspicious).", difficulty: 2, category: "Small Parts & Superficial", topic: "Thyroid" },
  { id: "sono-1067", stem: "Graves' disease on thyroid ultrasound typically shows:", options: ["Diffusely enlarged, hypoechoic gland with markedly increased vascularity ('thyroid inferno')","Atrophic gland","Focal hyperechoic mass","Normal-appearing gland"], correctIndex: 0, rationale: "Graves' disease: diffusely enlarged, hypoechoic gland with dramatically increased vascularity ('thyroid inferno' on color Doppler). Peak systolic velocities in thyroid arteries are elevated.", difficulty: 2, category: "Small Parts & Superficial", topic: "Thyroid" },
  { id: "sono-1068", stem: "A salivary gland stone (sialolithiasis) on ultrasound appears as:", options: ["Echogenic focus within the salivary duct with posterior acoustic shadowing and possible proximal duct dilation","Hypoechoic mass","Cystic lesion","Normal gland appearance"], correctIndex: 0, rationale: "Sialolithiasis: echogenic focus with shadow within Wharton's (submandibular) or Stensen's (parotid) duct. Proximal duct dilation indicates obstruction. Submandibular gland most commonly affected.", difficulty: 2, category: "Small Parts & Superficial", topic: "Salivary Glands" },
  { id: "sono-1069", stem: "A pilonidal cyst on ultrasound appears as:", options: ["A subcutaneous hypoechoic or heterogeneous fluid collection in the sacrococcygeal region, possibly with sinus tracts","A deeply located retroperitoneal mass","A normal finding","An intra-abdominal abscess"], correctIndex: 0, rationale: "Pilonidal cysts: subcutaneous collections in the natal cleft/sacrococcygeal area. US shows fluid collection, possible sinus tracts, and surrounding inflammation when infected.", difficulty: 2, category: "Small Parts & Superficial", topic: "Soft Tissue" },
  { id: "sono-1070", stem: "The normal neonatal hip on ultrasound should show:", options: ["Alpha angle ≥60° (Graf classification Type I), indicating adequate acetabular coverage of the femoral head","Alpha angle <45°","Femoral head completely uncovered","No ossified structures visible"], correctIndex: 0, rationale: "Graf classification: Type I (normal) has alpha angle ≥60°. Type IIa (physiologically immature <3 months), Type III/IV (dislocated). Used for developmental dysplasia of the hip screening.", difficulty: 3, category: "Small Parts & Superficial", topic: "Pediatric Hip" },
  { id: "sono-1071", stem: "Point-of-care ultrasound (POCUS) for pneumothorax looks for:", options: ["Absence of lung sliding, absence of B-lines, and the 'stratosphere sign' (barcode sign) on M-mode","Presence of A-lines alone","Pleural effusion","Lung consolidation only"], correctIndex: 0, rationale: "Pneumothorax: absent lung sliding, absent B-lines, 'barcode/stratosphere sign' on M-mode (vs normal 'seashore sign'). Lung point (transition from sliding to absent sliding) confirms the diagnosis.", difficulty: 3, category: "Abdominal Sonography", topic: "POCUS/E-FAST" },
  { id: "sono-1072", stem: "B-lines on lung ultrasound represent:", options: ["Vertical hyperechoic artifacts arising from the pleural line to the bottom of the screen, indicating interstitial syndrome (pulmonary edema)","Normal lung findings","Pneumothorax","Pleural effusion"], correctIndex: 0, rationale: "B-lines (lung rockets): vertical hyperechoic artifacts from pleural line moving with respiration. ≥3 per intercostal space = interstitial syndrome. Seen in pulmonary edema, pneumonia, ARDS.", difficulty: 2, category: "Abdominal Sonography", topic: "Lung Ultrasound" },
  { id: "sono-1073", stem: "The IVC diameter and collapsibility on ultrasound can estimate:", options: ["Right atrial pressure — a distended IVC with <50% inspiratory collapse suggests elevated RA pressure","Left ventricular EF","Pulmonary artery pressure directly","Renal function"], correctIndex: 0, rationale: "IVC assessment: <2.1cm with >50% collapse = normal RAP (~3mmHg). >2.1cm with <50% collapse = elevated RAP (~15mmHg). Used in fluid status and PAP estimation.", difficulty: 2, category: "Abdominal Sonography", topic: "POCUS" },
  { id: "sono-1074", stem: "Necrotizing enterocolitis (NEC) in neonates on ultrasound shows:", options: ["Pneumatosis intestinalis (air in bowel wall), portal venous gas, bowel wall thickening, and possible free air","Normal bowel appearance","Intussusception","Pyloric stenosis"], correctIndex: 0, rationale: "NEC: pneumatosis (echogenic foci in bowel wall), portal venous gas (echogenic foci in portal system), bowel wall thickening, ascites, absent peristalsis. Premature infants at highest risk.", difficulty: 3, category: "Abdominal Sonography", topic: "Pediatric" },
  { id: "sono-1075", stem: "A hepatoblastoma in a child on ultrasound appears as:", options: ["A large, solid, heterogeneous liver mass, often with calcifications, in a child under 3 years","A simple cyst","A normal liver variant","Only in adult livers"], correctIndex: 0, rationale: "Hepatoblastoma: most common primary hepatic malignancy in children <3 years. Solid, heterogeneous mass with possible calcifications. Elevated AFP. Right lobe more commonly affected.", difficulty: 3, category: "Abdominal Sonography", topic: "Pediatric Liver" },
  { id: "sono-1076", stem: "Wilms tumor (nephroblastoma) on ultrasound typically appears as:", options: ["A large, solid, heterogeneous renal mass in a child aged 1-5 years, often displacing normal kidney tissue","A small cortical cyst","An echogenic renal stone","A normal kidney variant"], correctIndex: 0, rationale: "Wilms tumor: most common pediatric renal malignancy, ages 1-5. Large solid mass arising from the kidney, heterogeneous, may have hemorrhage/necrosis. 5-10% are bilateral.", difficulty: 2, category: "Abdominal Sonography", topic: "Pediatric Renal" },
  { id: "sono-1077", stem: "The resistive index of the umbilical artery is calculated using the formula:", options: ["RI = (PSV - EDV) / PSV","RI = PSV / EDV","RI = EDV / PSV","RI = (PSV + EDV) / mean velocity"], correctIndex: 0, rationale: "RI = (PSV - EDV) / PSV. Normal umbilical artery RI decreases with advancing gestational age as placental resistance falls. Elevated RI indicates increased placental resistance.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Doppler" },
  { id: "sono-1078", stem: "In lower extremity venous duplex, the common femoral vein is assessed for DVT using:", options: ["Compression technique — inability to fully compress the vein indicates thrombus","Doppler velocity measurements only","B-mode brightness changes only","Color flow without compression"], correctIndex: 0, rationale: "Compression ultrasonography: the primary method for DVT diagnosis. Complete vein collapse with transducer pressure = no thrombus. Incomplete/absent compression = thrombus present.", difficulty: 1, category: "Vascular Sonography", topic: "Lower Extremity Venous" },
  { id: "sono-1079", stem: "Chronic DVT differs from acute DVT on ultrasound in that chronic DVT shows:", options: ["Echogenic, retracted thrombus with wall thickening, possible recanalization channels, and smaller vein caliber","Anechoic, distended vein","Completely normal-appearing vein","Increased vein diameter"], correctIndex: 0, rationale: "Acute DVT: anechoic/hypoechoic, distended vein. Chronic DVT: echogenic organized thrombus, contracted vein, wall thickening, collateral vessels, possible partial recanalization.", difficulty: 2, category: "Vascular Sonography", topic: "Lower Extremity Venous" },
  { id: "sono-1080", stem: "A carotid web is:", options: ["A thin shelf-like intraluminal projection in the posterior wall of the carotid bulb, associated with recurrent stroke","Atherosclerotic plaque","Carotid dissection","External carotid stenosis"], correctIndex: 0, rationale: "Carotid webs are intimal variant/fibromuscular shelf in the proximal ICA/bulb. Associated with cryptogenic stroke in young patients. Best seen on CTA but may be detected on US.", difficulty: 4, category: "Vascular Sonography", topic: "Carotid Pathology" },
  { id: "sono-1081", stem: "Mesenteric ischemia (acute) may show which Doppler findings in the SMA?", options: ["Absent flow or markedly elevated velocities (>275 cm/s PSV) at a stenosis, with decreased flow distally","Normal SMA velocities","Increased flow throughout","Reversed flow in the SMA"], correctIndex: 0, rationale: "Acute mesenteric ischemia: SMA occlusion (absent flow) or severe stenosis (PSV >275 cm/s, EDV >45 cm/s). Absent mesenteric flow is an emergency requiring surgical intervention.", difficulty: 4, category: "Vascular Sonography", topic: "Mesenteric Assessment" },
  { id: "sono-1082", stem: "An arteriovenous fistula (AVF) for dialysis access is monitored by ultrasound to assess:", options: ["Flow volume, stenosis, aneurysm, access depth, and maturation adequacy","Only fistula size","Patient blood pressure","Cardiac function"], correctIndex: 0, rationale: "Dialysis access surveillance: flow volume (>600 mL/min adequate), stenosis (PSV ratio >3:1), aneurysm/pseudoaneurysm, depth from skin, maturation, and steal syndrome.", difficulty: 3, category: "Vascular Sonography", topic: "Dialysis Access" },
  { id: "sono-1083", stem: "The popliteal entrapment syndrome involves:", options: ["Compression of the popliteal artery by an anomalous medial head of the gastrocnemius muscle, causing claudication","DVT in the popliteal vein","Baker's cyst compression","Popliteal aneurysm without compression"], correctIndex: 0, rationale: "Popliteal entrapment: anomalous muscle/fibrous band compresses the popliteal artery. Seen in young athletes. Dynamic provocative maneuvers (dorsiflexion) reproduce compression on Doppler.", difficulty: 4, category: "Vascular Sonography", topic: "Lower Extremity Arterial" },
  { id: "sono-1084", stem: "Proper transducer care includes:", options: ["Inspecting for cracks, cleaning between patients, never immersing beyond indicated depth, and proper storage","Only cleaning weekly","No maintenance required","Autoclaving all transducers after each use"], correctIndex: 0, rationale: "Transducer care: visual inspection (cracks, delamination), appropriate cleaning/disinfection level, not exceeding immersion limits, proper cable management, and upright storage.", difficulty: 1, category: "Patient Care & Safety", topic: "Equipment Care" },
  { id: "sono-1085", stem: "When a patient refuses an ultrasound examination, the sonographer should:", options: ["Respect the patient's right to refuse, document the refusal, and notify the referring physician","Perform the exam anyway","Ignore the refusal","Discharge the patient without documentation"], correctIndex: 0, rationale: "Patient autonomy includes the right to refuse examination. Document the refusal, notify the referring physician, and ensure the patient understands potential consequences.", difficulty: 1, category: "Patient Care & Safety", topic: "Patient Rights" },
  { id: "sono-1086", stem: "A Bosniak classification of renal cysts is used to:", options: ["Stratify renal cystic lesions by malignancy risk from simple cysts (I) to clearly malignant (IV)","Only classify solid renal masses","Stage renal cell carcinoma","Evaluate renal function"], correctIndex: 0, rationale: "Bosniak: I (simple, benign), II (minimally complex), IIF (follow-up needed), III (indeterminate), IV (clearly malignant). Based on septations, calcification, enhancement, nodularity.", difficulty: 3, category: "Abdominal Sonography", topic: "Renal Cysts" },
  { id: "sono-1087", stem: "An O-RADS score of 5 on ultrasound indicates:", options: ["High risk of malignancy (≥50% malignancy rate), requiring surgical evaluation","A simple benign cyst","Normal ovary","Low risk finding"], correctIndex: 0, rationale: "O-RADS US: 1=normal, 2=almost certainly benign, 3=low risk, 4=intermediate risk, 5=high risk (≥50%). Scoring based on lesion size, solid components, ascites, color score.", difficulty: 3, category: "OB/GYN Sonography", topic: "Ovarian Mass Classification" },
  { id: "sono-1088", stem: "Focused Assessment with Sonography for HIV (FASH) evaluates:", options: ["Pericardial effusion, pleural effusion, ascites, focal splenic/hepatic lesions, and abdominal lymphadenopathy in HIV patients","Only cardiac function","Brain lesions","Only pulmonary lesions"], correctIndex: 0, rationale: "FASH protocol for HIV-associated TB and other infections: pericardial effusion, pleural effusion, ascites, hepatic/splenic microabscesses, and abdominal lymphadenopathy.", difficulty: 4, category: "Abdominal Sonography", topic: "POCUS Protocols" },
  { id: "sono-1089", stem: "Acoustic power output in ultrasound is measured in:", options: ["Milliwatts (mW) or watts (W)","Hertz","Decibels","Meters per second"], correctIndex: 0, rationale: "Acoustic power (total energy per unit time) is measured in milliwatts or watts. Intensity (power/area) is measured in mW/cm². Both relate to bioeffect potential.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Physics Fundamentals" },
  { id: "sono-1090", stem: "The half-value layer thickness in ultrasound refers to:", options: ["The tissue thickness required to reduce ultrasound intensity by half (3 dB)","The depth at which resolution is best","The transducer element thickness","The focal zone depth"], correctIndex: 0, rationale: "Half-value layer: tissue thickness that attenuates the beam intensity by 50% (3 dB). Depends on frequency and tissue type. Higher frequency = thinner HVL = less penetration.", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Physics Fundamentals" },
  { id: "sono-1091", stem: "Quality assurance testing for ultrasound equipment should include:", options: ["AIUM phantom testing for spatial resolution, contrast resolution, distance accuracy, and dead zone measurement","Only checking image brightness","Annual calibration only","No routine testing is required"], correctIndex: 0, rationale: "QA phantom testing evaluates: axial/lateral resolution, depth accuracy, dead zone, sensitivity (penetration), gray scale/dynamic range, and geometric accuracy. Performed regularly.", difficulty: 2, category: "Patient Care & Safety", topic: "Quality Assurance" },
  { id: "sono-1092", stem: "Tissue Doppler imaging (TDI) in ultrasound measures:", options: ["Low-velocity, high-amplitude signals from myocardial tissue motion, used to assess diastolic function","High-velocity blood flow signals","Only valve motion","Bone density"], correctIndex: 0, rationale: "TDI captures myocardial velocities (e', a', s') by filtering out high-velocity/low-amplitude blood signals. Primary application: diastolic function assessment (E/e' ratio).", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Doppler Techniques" },
  { id: "sono-1093", stem: "In second-trimester anatomy scan, the four-chamber heart view should demonstrate:", options: ["Both atria and ventricles approximately equal in size, intact interventricular septum, two functional AV valves, and the heart occupying about one-third of the thorax","Only the left ventricle","Three chambers","The heart filling the entire thorax"], correctIndex: 0, rationale: "Normal fetal four-chamber view: symmetric chambers, intact IVS, offset AV valves (tricuspid slightly more apical), cardiac axis ~45° left, heart = ~1/3 thoracic area.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Cardiac Screening" },
  { id: "sono-1094", stem: "Uterine artery embolization (UAE) follow-up by ultrasound shows:", options: ["Decreased fibroid size and vascularity with possible areas of necrosis/degeneration","Increased fibroid size","New fibroid growth in all cases","Normal uterine appearance immediately"], correctIndex: 0, rationale: "Post-UAE: fibroids typically shrink 40-60% by 6 months, show decreased vascularity and possible cystic degeneration/necrosis. Ultrasound monitors treatment response.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fibroid Treatment" },
  { id: "sono-1095", stem: "The preauricular lymph nodes drain:", options: ["The superficial face, temporal scalp, and external ear","The lungs","The abdominal organs","The lower extremities"], correctIndex: 0, rationale: "Preauricular (parotid) nodes drain the lateral face, temporal scalp, external ear, and lateral eyelids. Important for evaluating facial/ear pathology and melanoma staging.", difficulty: 3, category: "Small Parts & Superficial", topic: "Lymph Node Anatomy" },
  { id: "sono-1096", stem: "Ultrasound-guided thyroid FNA is indicated for nodules classified as:", options: ["TI-RADS 4 (≥15mm) and TI-RADS 5 (≥10mm), with lower categories followed rather than biopsied","All thyroid nodules regardless of size or features","Only cystic nodules","Only calcified nodules"], correctIndex: 0, rationale: "ACR TI-RADS recommends FNA based on size thresholds tied to suspicion level. Higher suspicion = smaller size threshold for biopsy. TR1-2: no FNA. TR3: FNA ≥25mm. TR4: ≥15mm. TR5: ≥10mm.", difficulty: 3, category: "Small Parts & Superficial", topic: "Thyroid FNA" },
  { id: "sono-1097", stem: "A testicular microlithiasis finding on ultrasound:", options: ["Shows multiple tiny echogenic foci (≥5 per field) within the testis; clinical significance is debated but follow-up may be recommended","Is always associated with malignancy","Requires immediate orchiectomy","Is a normal variant requiring no follow-up"], correctIndex: 0, rationale: "Testicular microlithiasis: ≥5 echogenic foci per transducer field. Association with malignancy is debated. Follow-up recommended in patients with risk factors (cryptorchidism, prior tumor).", difficulty: 3, category: "Small Parts & Superficial", topic: "Scrotal" },
  { id: "sono-1098", stem: "Duplex scanning of a carotid artery stent should show:", options: ["In-stent velocities appropriate for the stent type (generally PSV <150 cm/s and ICA/CCA ratio <2.15 for patent stent)","No flow within the stent","Very high velocities always","Identical velocities to native vessels"], correctIndex: 0, rationale: "Post-stent surveillance: elevated baseline velocities within stents are common. Significant in-stent restenosis suggested by PSV >220-300 cm/s (varies by criteria). Regular surveillance recommended.", difficulty: 4, category: "Vascular Sonography", topic: "Carotid Stent" },
  { id: "sono-1099", stem: "Superficial thrombophlebitis on ultrasound shows:", options: ["Non-compressible superficial vein with intraluminal echoes and surrounding soft tissue inflammation","Deep vein thrombus","Normal superficial veins","Arterial occlusion"], correctIndex: 0, rationale: "Superficial thrombophlebitis: non-compressible superficial vein, intraluminal thrombus, perivenous edema/inflammation. Important to rule out extension into deep veins at saphenofemoral junction.", difficulty: 2, category: "Vascular Sonography", topic: "Superficial Venous" },
  { id: "sono-1100", stem: "The proper gain setting for an ultrasound image should:", options: ["Display a uniform brightness throughout the image with blood-filled structures appearing anechoic and soft tissue showing appropriate gray scale","Maximize brightness at all depths","Show all structures as white","Be set to minimum at all times"], correctIndex: 0, rationale: "Optimal gain: blood vessels/fluid anechoic, soft tissue appropriately gray, no excessive noise. Use overall gain and TGC together for uniform image throughout all depths.", difficulty: 1, category: "Ultrasound Physics & Instrumentation", topic: "Image Optimization" },
  { id: "sono-1101", stem: "Color Doppler aliasing can be corrected by:", options: ["Increasing the PRF (velocity scale), lowering the baseline, or using a lower-frequency Doppler","Decreasing the PRF","Increasing the color gain","Changing to B-mode only"], correctIndex: 0, rationale: "Color aliasing occurs when flow velocity exceeds Nyquist limit (PRF/2). Solutions: increase PRF/scale, lower baseline, decrease frequency, increase angle. Power Doppler doesn't alias.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Doppler Optimization" },
  { id: "sono-1102", stem: "A complete carotid duplex examination should include:", options: ["B-mode, color Doppler, and spectral Doppler of CCA, ICA, ECA, and vertebral arteries bilaterally","Only ICA velocity measurement","Only B-mode imaging","Only color Doppler without spectral analysis"], correctIndex: 0, rationale: "Complete carotid duplex: bilateral B-mode (plaque), color Doppler (flow patterns), and spectral Doppler (velocities) of CCA, bifurcation, ICA, ECA, and vertebral arteries.", difficulty: 1, category: "Vascular Sonography", topic: "Carotid Protocol" },
  { id: "sono-1103", stem: "Contrast-enhanced ultrasound (CEUS) of the liver is useful for:", options: ["Characterizing focal liver lesions by demonstrating enhancement patterns in arterial, portal venous, and late phases","Only measuring liver size","Only evaluating bile ducts","Replacing all other liver imaging"], correctIndex: 0, rationale: "CEUS shows lesion enhancement in real-time through three phases. FNH: centrifugal arterial enhancement. HCC: arterial hyperenhancement with late washout. Hemangioma: peripheral nodular enhancement.", difficulty: 3, category: "Abdominal Sonography", topic: "Contrast Enhancement" },
  { id: "sono-1104", stem: "The cerebro-placental ratio (CPR) in fetal assessment is:", options: ["MCA PI divided by umbilical artery PI — CPR <1.0 suggests fetal redistribution of blood flow (brain sparing)","Umbilical artery PI divided by MCA PI","BPD divided by AC","FL divided by HC"], correctIndex: 0, rationale: "CPR = MCA PI / UA PI. CPR <1.0 (or <5th percentile for GA) indicates fetal blood flow redistribution with preferential perfusion to the brain, associated with adverse outcomes.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Doppler" },
  { id: "sono-1105", stem: "A proper ergonomic scanning position for the sonographer includes:", options: ["Elbow close to the body, wrist neutral, adjustable chair height, monitor at eye level, and patient bed at appropriate height","Arm fully extended","Wrist hyperflexed","Standing on one leg"], correctIndex: 0, rationale: "Ergonomic positioning reduces WRMSD risk: elbow angle ~90°, arm close to body, neutral wrist, adjustable equipment, proper bed/chair height, monitor at eye level, frequent breaks.", difficulty: 1, category: "Patient Care & Safety", topic: "Ergonomics" },
];
